
const ARTWORKS = [{"title": "Mona Lisa", "artist": "Leonardo da Vinci", "year": "c. 1503–1506", "movement": "High Renaissance", "location": "Louvre Museum, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Mona%20Lisa%2C%20by%20Leonardo%20da%20Vinci%2C%20from%20C2RMF%20retouched.jpg", "whySpecial": "It is not famous only because of the smile. Leonardo made a portrait feel psychologically alive: calm, ambiguous and impossible to fully settle.", "notice": ["Soft transitions around the mouth and eyes, known as sfumato.", "The sitter turns toward us, creating quiet presence.", "The landscape feels dreamlike rather than documentary.", "There are almost no hard outlines."], "whyKnow": "It is the global symbol of portrait painting and Renaissance curiosity about the human mind.", "lesson": "Great portraiture is not just likeness. It is tension between what is shown and what remains hidden."}, {"title": "The Starry Night", "artist": "Vincent van Gogh", "year": "1889", "movement": "Post-Impressionism", "location": "Museum of Modern Art, New York", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Van%20Gogh%20-%20Starry%20Night%20-%20Google%20Art%20Project.jpg", "whySpecial": "Van Gogh turns the night sky into emotion. The painting shows movement, pressure, loneliness and spiritual energy rather than optical realism.", "notice": ["The sky is built from swirling brushstrokes.", "The cypress tree rises like a dark flame.", "The village is quiet while the sky is restless.", "The stars glow like emotional events."], "whyKnow": "It is one of the clearest examples of modern art moving from realism toward inner experience.", "lesson": "A painting can show not only what a place looks like, but what it feels like inside a human mind."}, {"title": "Girl with a Pearl Earring", "artist": "Johannes Vermeer", "year": "c. 1665", "movement": "Dutch Golden Age", "location": "Mauritshuis, The Hague", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Meisje%20met%20de%20parel.jpg", "whySpecial": "This is less a portrait than a moment. Vermeer creates intimacy with light, silence and a glance.", "notice": ["The dark background removes distraction.", "The pearl is painted with very few strokes.", "The open mouth creates immediacy.", "The blue and yellow headscarf feels theatrical."], "whyKnow": "It teaches the power of restraint and atmosphere.", "lesson": "Sometimes the most memorable art does not explain itself. It invites you into a pause."}, {"title": "The Birth of Venus", "artist": "Sandro Botticelli", "year": "c. 1485", "movement": "Early Renaissance", "location": "Uffizi Gallery, Florence", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Sandro%20Botticelli%20-%20La%20nascita%20di%20Venere%20-%20Google%20Art%20Project%20-%20edited.jpg", "whySpecial": "Botticelli brings classical mythology into Renaissance beauty. Venus appears as an ideal, poetic image rather than a realistic body.", "notice": ["The pose is elegant but anatomically impossible in places.", "The lines are flowing and decorative.", "Venus stands at the centre like an icon.", "Wind, hair and fabric create graceful movement."], "whyKnow": "It is a key image of Renaissance humanism and the rebirth of classical culture.", "lesson": "Renaissance art was also visual poetry, not only realism."}, {"title": "Las Meninas", "artist": "Diego Velázquez", "year": "1656", "movement": "Spanish Baroque", "location": "Museo del Prado, Madrid", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Las%20Meninas%2C%20by%20Diego%20Vel%C3%A1zquez%2C%20from%20Prado%20in%20Google%20Earth.jpg", "whySpecial": "One of the cleverest paintings ever made about looking. Are we seeing the royal family, the painter, the princess, or ourselves?", "notice": ["Velázquez paints himself inside the painting.", "The mirror shows the king and queen.", "The viewer seems to stand where the monarchs stand.", "The room feels casual but is highly controlled."], "whyKnow": "It changed how people think about artist, subject and viewer.", "lesson": "A painting can be a puzzle about perception."}, {"title": "The Great Wave off Kanagawa", "artist": "Katsushika Hokusai", "year": "c. 1831", "movement": "Ukiyo-e", "location": "Various collections", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Great%20Wave%20off%20Kanagawa2.jpg", "whySpecial": "The wave is beautiful and threatening. Hokusai turns nature into a graphic force with rhythm, contrast and clarity.", "notice": ["Mount Fuji is tiny, making the wave feel enormous.", "The foam almost looks like claws.", "The boats are trapped inside the movement.", "The limited palette makes it unforgettable."], "whyKnow": "It introduced many Western audiences to Japanese printmaking and influenced modern European artists.", "lesson": "An image can be simple, decorative and terrifying at the same time."}, {"title": "The School of Athens", "artist": "Raphael", "year": "1509–1511", "movement": "High Renaissance", "location": "Apostolic Palace, Vatican City", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/La%20scuola%20di%20Atene.jpg", "whySpecial": "This fresco is the Renaissance dream of knowledge: philosophy, mathematics and beauty gathered in one ordered space.", "notice": ["Plato points upward; Aristotle gestures toward the world.", "Perspective pulls the eye to the centre.", "Groups create rhythm without chaos.", "The scene is intellectual and theatrical."], "whyKnow": "It shows the Renaissance belief that art, science and philosophy belong together.", "lesson": "Composition can be an argument."}, {"title": "The Night Watch", "artist": "Rembrandt van Rijn", "year": "1642", "movement": "Dutch Golden Age / Baroque", "location": "Rijksmuseum, Amsterdam", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Rembrandt%20-%20The%20Nightwatch%20-%20Google%20Art%20Project.jpg", "whySpecial": "Rembrandt turns a group portrait into drama. The figures move, gesture and emerge from shadow like a scene unfolding.", "notice": ["Light selects certain figures, not everyone equally.", "The diagonal composition creates action.", "The girl in gold is symbolic and mysterious.", "It feels cinematic before cinema existed."], "whyKnow": "It is a landmark in Baroque drama and group portraiture.", "lesson": "Light can direct attention like a spotlight."}, {"title": "The Arnolfini Portrait", "artist": "Jan van Eyck", "year": "1434", "movement": "Northern Renaissance", "location": "National Gallery, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Van%20Eyck%20-%20Arnolfini%20Portrait.jpg", "whySpecial": "A masterpiece of detail, symbolism and oil-painting technique. Almost every object feels like a clue.", "notice": ["The convex mirror reflects figures entering the room.", "Textures of fur, wood, metal and fabric are precise.", "The dog may suggest loyalty.", "Van Eyck signs the wall like a witness."], "whyKnow": "It is central to Northern Renaissance symbolic detail.", "lesson": "Details are not decoration here. They are evidence."}, {"title": "The Creation of Adam", "artist": "Michelangelo", "year": "c. 1512", "movement": "High Renaissance", "location": "Sistine Chapel, Vatican City", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Michelangelo%20-%20Creation%20of%20Adam%20%28cropped%29.jpg", "whySpecial": "The almost-touching fingers create one of the most powerful gaps in art history.", "notice": ["Adam’s body is idealised but not fully animated.", "God moves with urgency.", "The hands are close but not touching.", "The empty gap creates suspense."], "whyKnow": "It is a central image of Renaissance humanity, divinity and creation.", "lesson": "Sometimes the most important part of an image is the space between things."}, {"title": "The Scream", "artist": "Edvard Munch", "year": "1893", "movement": "Expressionism / Symbolism", "location": "National Museum, Oslo", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Edvard%20Munch%20-%20The%20Scream%20-%20Google%20Art%20Project.jpg", "whySpecial": "Munch gives anxiety a visual form. The world itself seems to vibrate with panic.", "notice": ["The figure is simplified almost into a skull.", "The sky and landscape ripple emotionally.", "The bridge creates sharp perspective.", "The background figures feel detached."], "whyKnow": "It is one of the key images of modern psychological anxiety.", "lesson": "Expressionism asks what fear feels like, not what the world looks like."}, {"title": "The Persistence of Memory", "artist": "Salvador Dalí", "year": "1931", "movement": "Surrealism", "location": "Museum of Modern Art, New York", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/The%20Persistence%20of%20Memory.jpg", "whySpecial": "Dalí makes time soft, unstable and dreamlike. The melting clocks are absurd but unforgettable.", "notice": ["Hard objects behave like soft material.", "The empty landscape feels dreamlike.", "The central form is ambiguous and unsettling.", "The image is small but conceptually huge."], "whyKnow": "It is one of the most famous images of Surrealism.", "lesson": "Surrealism makes impossible things feel strangely precise."}, {"title": "The Kiss", "artist": "Gustav Klimt", "year": "1907–1908", "movement": "Symbolism / Vienna Secession", "location": "Belvedere, Vienna", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/The%20Kiss%20-%20Gustav%20Klimt%20-%20Google%20Cultural%20Institute.jpg", "whySpecial": "Klimt turns intimacy into pattern, gold and ornament. The bodies almost disappear into decoration.", "notice": ["Gold makes the image feel sacred and luxurious.", "The two figures form one decorative shape.", "Patterns differ between the figures.", "The flowered edge adds tension."], "whyKnow": "It is a defining image of fin-de-siècle Vienna and decorative modernism.", "lesson": "Decoration is not superficial when pattern becomes emotion."}, {"title": "Impression, Sunrise", "artist": "Claude Monet", "year": "1872", "movement": "Impressionism", "location": "Musée Marmottan Monet, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Claude%20Monet%2C%20Impression%2C%20soleil%20levant.jpg", "whySpecial": "This painting helped give Impressionism its name. It captures a fleeting effect of light rather than a polished scene.", "notice": ["Brushwork is loose and visible.", "The orange sun dominates the atmosphere.", "Boats are suggested with minimal detail.", "The scene feels temporary."], "whyKnow": "It marks a turning point toward modern painting: perception over precision.", "lesson": "Sometimes the impression matters more than the object."}, {"title": "American Gothic", "artist": "Grant Wood", "year": "1930", "movement": "Regionalism", "location": "Art Institute of Chicago", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Grant%20Wood%20-%20American%20Gothic%20-%20Google%20Art%20Project.jpg", "whySpecial": "It looks simple but remains ambiguous: sincere, satirical, respectful and uncomfortable at once.", "notice": ["The pitchfork repeats vertical lines in the house and clothes.", "The figures stare directly but reveal little.", "The Gothic window gives the title.", "The tight composition creates pressure."], "whyKnow": "It became one of the most recognisable images of American identity.", "lesson": "Iconic images survive because they keep changing meaning."}, {"title": "The Third of May 1808", "artist": "Francisco Goya", "year": "1814", "movement": "Romanticism", "location": "Museo del Prado, Madrid", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/El%20Tres%20de%20Mayo%2C%20by%20Francisco%20de%20Goya%2C%20from%20Prado%20thin%20black%20margin.jpg", "whySpecial": "Goya strips war of glory. The central victim becomes a martyr while the soldiers become a faceless machine.", "notice": ["The lantern creates brutal theatrical light.", "The soldiers are anonymous and mechanical.", "The white shirt makes the victim the focus.", "The bodies show what is about to happen."], "whyKnow": "It is one of the first great modern anti-war paintings.", "lesson": "Art can refuse heroism and still be monumental."}, {"title": "The Fighting Temeraire", "artist": "J. M. W. Turner", "year": "1839", "movement": "Romanticism", "location": "National Gallery, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Turner%2C%20The%20Fighting%20Temeraire%2C%201839.jpg", "whySpecial": "Turner paints the end of an era: an old warship pulled by a modern steam tug.", "notice": ["The old ship looks pale and ghostlike.", "The tug is dark and practical.", "The sunset creates farewell.", "The scene is about mood as much as history."], "whyKnow": "It is one of the great paintings about modernity replacing the past.", "lesson": "Landscape can carry historical emotion."}, {"title": "Wanderer above the Sea of Fog", "artist": "Caspar David Friedrich", "year": "c. 1818", "movement": "Romanticism", "location": "Hamburger Kunsthalle, Hamburg", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Caspar%20David%20Friedrich%20-%20Wanderer%20above%20the%20Sea%20of%20Fog.jpeg", "whySpecial": "This captures the Romantic sublime: nature as beautiful, overwhelming and spiritually charged.", "notice": ["We see the figure from behind, so we look with him.", "Fog hides as much as it reveals.", "The human is central but small.", "The pose suggests control; nature suggests mystery."], "whyKnow": "It is a key image of Romanticism and the modern individual facing nature.", "lesson": "The sublime is beauty mixed with uncertainty and awe."}, {"title": "The Milkmaid", "artist": "Johannes Vermeer", "year": "c. 1658–1660", "movement": "Dutch Golden Age", "location": "Rijksmuseum, Amsterdam", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Johannes%20Vermeer%20-%20Het%20melkmeisje%20-%20Google%20Art%20Project.jpg", "whySpecial": "Vermeer turns an ordinary domestic action into a study of light, attention and dignity.", "notice": ["Light enters from the left and shapes everything.", "The figure is absorbed in her task.", "Bread and ceramics have tactile weight.", "The plain wall has subtle colour shifts."], "whyKnow": "It shows how Dutch painting could elevate everyday life.", "lesson": "Attention is a form of respect."}, {"title": "The Last Supper", "artist": "Leonardo da Vinci", "year": "1495–1498", "movement": "High Renaissance", "location": "Santa Maria delle Grazie, Milan", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/%C3%9Altima%20Cena%20-%20Da%20Vinci%205.jpg", "whySpecial": "Leonardo turns a religious scene into a study of reaction. Each apostle responds differently to Christ’s announcement of betrayal.", "notice": ["Christ is the calm centre of the composition.", "The apostles are arranged in groups of three.", "Perspective lines lead toward Christ’s head.", "The gestures create psychological drama."], "whyKnow": "It is a masterclass in composition, narrative clarity and emotional variety.", "lesson": "A great composition can organise chaos without killing emotion."}, {"title": "Primavera", "artist": "Sandro Botticelli", "year": "c. 1482", "movement": "Early Renaissance", "location": "Uffizi Gallery, Florence", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/La%20Primavera%20%28Botticelli%29.jpg", "whySpecial": "Primavera is a mysterious mythological scene filled with rhythm, elegance and symbolic figures. It feels like poetry more than narrative.", "notice": ["The figures are arranged like dancers.", "The dark grove makes the pale figures stand out.", "The flowers are carefully detailed.", "The scene is beautiful but not easy to decode."], "whyKnow": "It is key for understanding myth, beauty and humanist culture in Renaissance Florence.", "lesson": "Some paintings survive because they remain open."}, {"title": "The Garden of Earthly Delights", "artist": "Hieronymus Bosch", "year": "c. 1490–1510", "movement": "Early Netherlandish", "location": "Museo del Prado, Madrid", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Hieronymus%20Bosch%20-%20The%20Garden%20of%20Earthly%20Delights%20-%20The%20central%20panel%20-%20Google%20Art%20Project.jpg", "whySpecial": "Bosch creates a world that feels like dream, warning and hallucination, crowded with strange creatures, pleasures and punishments.", "notice": ["The image is crowded but carefully organised.", "Bodies appear playful, vulnerable and absurd.", "Animals, fruit and hybrids create symbolic overload.", "The painting rewards slow looking."], "whyKnow": "It is one of the strangest and most influential works in European art.", "lesson": "Some art does not simplify the world. It makes its weirdness impossible to ignore."}, {"title": "The Ambassadors", "artist": "Hans Holbein the Younger", "year": "1533", "movement": "Northern Renaissance", "location": "National Gallery, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Hans%20Holbein%20the%20Younger%20-%20The%20Ambassadors%20-%20Google%20Art%20Project.jpg", "whySpecial": "This portrait is full of learning, status and illusion. Its famous distorted skull only makes sense from the side.", "notice": ["Objects show knowledge: globes, instruments and books.", "The figures project wealth and confidence.", "The skull is anamorphic.", "The painting mixes worldly success with mortality."], "whyKnow": "It is a great example of Renaissance symbolism and optical trickery.", "lesson": "Perspective can reveal truth only when you change position."}, {"title": "Liberty Leading the People", "artist": "Eugène Delacroix", "year": "1830", "movement": "Romanticism", "location": "Louvre Museum, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Eug%C3%A8ne%20Delacroix%20-%20La%20libert%C3%A9%20guidant%20le%20peuple.jpg", "whySpecial": "Delacroix turns a political uprising into myth. Liberty is both a woman in the street and an allegorical force.", "notice": ["The composition rises toward the flag.", "Liberty is idealised but surrounded by real bodies.", "The French flag colours structure the image.", "Beauty, violence and politics mix together."], "whyKnow": "It is one of the defining images of revolutionary Romanticism.", "lesson": "Political art often turns events into symbols people can remember."}, {"title": "The Raft of the Medusa", "artist": "Théodore Géricault", "year": "1818–1819", "movement": "Romanticism", "location": "Louvre Museum, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/JEAN%20LOUIS%20TH%C3%89ODORE%20G%C3%89RICAULT%20-%20La%20Balsa%20de%20la%20Medusa%20%28Museo%20del%20Louvre%2C%201818-19%29.jpg", "whySpecial": "Géricault turns a contemporary disaster into an epic image of suffering, hope and political failure.", "notice": ["Bodies form a rising diagonal toward the rescue ship.", "The scene is physically brutal and theatrical.", "Hope and despair share one composition.", "The scale makes a news event feel historical."], "whyKnow": "It is a landmark of Romanticism and politically charged history painting.", "lesson": "Scale can turn journalism into tragedy."}, {"title": "The Swing", "artist": "Jean-Honoré Fragonard", "year": "1767", "movement": "Rococo", "location": "Wallace Collection, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Fragonard%2C%20The%20Swing.jpg", "whySpecial": "The Swing is playful, theatrical and flirtatious, capturing Rococo taste for pleasure, softness and secret games.", "notice": ["The garden feels lush and artificial.", "The flying shoe adds humour and movement.", "The colours are soft and sweet.", "The composition hides a mischievous narrative."], "whyKnow": "It is one of the clearest examples of Rococo style and aristocratic leisure.", "lesson": "Style can reveal a whole social world: its pleasures, fantasies and blind spots."}, {"title": "Olympia", "artist": "Édouard Manet", "year": "1863", "movement": "Realism / Modernism", "location": "Musée d’Orsay, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Edouard%20Manet%20-%20Olympia%20-%20Google%20Art%20Project%203.jpg", "whySpecial": "Olympia shocked viewers because she looks back without shame or mythological disguise. Manet confronts the viewer with modern life.", "notice": ["The pose echoes classical nudes but removes idealisation.", "The gaze is direct and controlled.", "The brushwork is flatter than academic painting.", "The black cat adds tension."], "whyKnow": "It is a key painting in the birth of modern art.", "lesson": "Modern art often begins when old forms are reused to say something uncomfortable."}, {"title": "Luncheon on the Grass", "artist": "Édouard Manet", "year": "1863", "movement": "Realism / Modernism", "location": "Musée d’Orsay, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Edouard%20Manet%20-%20Luncheon%20on%20the%20Grass%20-%20Google%20Art%20Project.jpg", "whySpecial": "This painting scandalised viewers by placing a nude woman in a modern setting with clothed men, without mythological excuse.", "notice": ["The woman looks directly at the viewer.", "The space feels deliberately flattened.", "The picnic scene is casual but unsettling.", "Manet quotes older art while breaking its rules."], "whyKnow": "It helped push painting toward modernism.", "lesson": "Modern art often attacks expectations before it attacks the eye."}, {"title": "A Sunday Afternoon on the Island of La Grande Jatte", "artist": "Georges Seurat", "year": "1884–1886", "movement": "Neo-Impressionism / Pointillism", "location": "Art Institute of Chicago", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Georges%20Seurat%20-%20A%20Sunday%20on%20La%20Grande%20Jatte%20--%201884%20-%20Google%20Art%20Project.jpg", "whySpecial": "Seurat built a monumental scene from tiny dots of colour. It is scientific, elegant and strangely frozen.", "notice": ["The figures are still, almost like statues.", "Colour is made from dots placed side by side.", "The composition is carefully balanced.", "Leisure feels calm but artificial."], "whyKnow": "It shows artists experimenting with optics, colour theory and modern urban life.", "lesson": "Technique can change how time feels."}, {"title": "Whistler’s Mother", "artist": "James McNeill Whistler", "year": "1871", "movement": "Realism / Aestheticism", "location": "Musée d’Orsay, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Whistlers%20Mother%20high%20res.jpg", "whySpecial": "Famous as an image of motherhood, but Whistler saw it as an arrangement of shapes, tones and balance.", "notice": ["The side profile creates stillness.", "The palette is quiet: greys, blacks and muted tones.", "Rectangular frames echo the seated figure.", "Emotion is controlled, not sentimental."], "whyKnow": "It explains the idea that painting can be about composition and harmony, not only subject matter.", "lesson": "A painting can be emotional because it refuses to over-explain emotion."}, {"title": "The Hay Wain", "artist": "John Constable", "year": "1821", "movement": "English Romantic Landscape", "location": "National Gallery, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/John%20Constable%20-%20The%20Hay%20Wain%20%28National%20Gallery%2C%20London%29.jpg", "whySpecial": "Constable makes countryside feel observed, lived-in and atmospheric rather than idealised fantasy.", "notice": ["The clouds feel carefully studied.", "Water, cart and trees create rural rhythm.", "Ordinary labour matters.", "The light feels specific to a real moment."], "whyKnow": "It shaped later landscape painting and influenced French artists.", "lesson": "Landscape painting can be radical when it takes ordinary places seriously."}, {"title": "Guernica", "artist": "Pablo Picasso", "year": "1937", "movement": "Cubism / Modernism", "location": "Museo Reina Sofía, Madrid", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/PicassoGuernica.jpg", "whySpecial": "Guernica turns the bombing of a town into a universal image of civilian suffering and political horror.", "notice": ["The palette is black, white and grey, like newsprint and mourning.", "Bodies are fragmented and screaming.", "The horse and bull resist simple interpretation.", "The scale makes the viewer feel surrounded by violence."], "whyKnow": "It is one of the most important anti-war artworks of the twentieth century.", "lesson": "Modern art can make trauma visible without illustrating it literally."}, {"title": "Les Demoiselles d’Avignon", "artist": "Pablo Picasso", "year": "1907", "movement": "Cubism / Modernism", "location": "Museum of Modern Art, New York", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Les%20Demoiselles%20d%27Avignon.jpg", "whySpecial": "This painting breaks the body into sharp planes and attacks Renaissance ideas of beauty, space and perspective.", "notice": ["The figures are angular and confrontational.", "Faces draw from Iberian and African visual sources.", "Space feels shattered rather than deep.", "The viewer is not allowed to remain comfortable."], "whyKnow": "It is often treated as a breakthrough toward Cubism and modern art.", "lesson": "Sometimes art changes history by becoming difficult to look at."}, {"title": "Composition VII", "artist": "Wassily Kandinsky", "year": "1913", "movement": "Abstract Art", "location": "Tretyakov Gallery, Moscow", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Vassily%20Kandinsky%2C%201913%20-%20Composition%207.jpg", "whySpecial": "Kandinsky pushes painting toward pure abstraction: colour, rhythm and form without a conventional subject.", "notice": ["Forms collide like music.", "Colour creates emotional temperature.", "The composition feels chaotic but orchestrated.", "You look for rhythm rather than objects."], "whyKnow": "It is a milestone in abstract art.", "lesson": "Abstraction asks you to read energy, not objects."}, {"title": "Black Square", "artist": "Kazimir Malevich", "year": "1915", "movement": "Suprematism", "location": "Tretyakov Gallery, Moscow", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Kazimir%20Malevich%2C%201915%2C%20Black%20Suprematic%20Square%2C%20oil%20on%20linen%20canvas%2C%2079.5%20x%2079.5%20cm%2C%20Tretyakov%20Gallery%2C%20Moscow.jpg", "whySpecial": "Malevich reduces painting to a black square, turning absence into a radical statement about art’s future.", "notice": ["It rejects illusion, narrative and representation.", "The square is simple but aggressive.", "The surface is not perfectly flat.", "It behaves like an icon of modernism."], "whyKnow": "It is one of the most radical gestures in modern art.", "lesson": "Sometimes the shock is not complexity. It is refusal."}, {"title": "The Son of Man", "artist": "René Magritte", "year": "1964", "movement": "Surrealism", "location": "Private collection", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Magritte%20TheSonOfMan.jpg", "whySpecial": "Magritte makes the familiar strange. A man in a bowler hat becomes unknowable because an apple blocks his face.", "notice": ["The setting is ordinary but impossible.", "The apple hides identity while attracting attention.", "The suit suggests social normality.", "The image is clear and mysterious at once."], "whyKnow": "It is one of Surrealism’s most recognisable images about identity and concealment.", "lesson": "Mystery can be sharper when painted with perfect clarity."}, {"title": "Nighthawks", "artist": "Edward Hopper", "year": "1942", "movement": "American Realism", "location": "Art Institute of Chicago", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Nighthawks%20by%20Edward%20Hopper%201942.jpg", "whySpecial": "Hopper turns a late-night diner into an image of modern loneliness, light and urban silence.", "notice": ["The glass separates viewers from the figures.", "The street is empty.", "The light is harsh and theatrical.", "The figures are near each other but emotionally distant."], "whyKnow": "It became one of the great images of twentieth-century urban isolation.", "lesson": "Loneliness can be painted through architecture and light."}, {"title": "The Kiss", "artist": "Francesco Hayez", "year": "1859", "movement": "Italian Romanticism", "location": "Pinacoteca di Brera, Milan", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Francesco%20Hayez%20017.jpg", "whySpecial": "Hayez turns a kiss into a political and romantic symbol, full of secrecy, urgency and national feeling.", "notice": ["The embrace is passionate but tense.", "The foot on the step suggests departure.", "The medieval setting adds drama.", "Colour contrasts intensify emotion."], "whyKnow": "It is one of the iconic paintings of Italian Romanticism.", "lesson": "A romantic scene can also carry political meaning."}, {"title": "Ophelia", "artist": "John Everett Millais", "year": "1851–1852", "movement": "Pre-Raphaelite", "location": "Tate Britain, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/John%20Everett%20Millais%20-%20Ophelia%20-%20Google%20Art%20Project.jpg", "whySpecial": "Millais paints beauty and death with unsettling precision. Ophelia floats in a world of flowers, water and silence.", "notice": ["The plants are botanically detailed.", "The body seems both weightless and tragic.", "The open hands suggest surrender.", "Nature is beautiful but indifferent."], "whyKnow": "It is a defining Pre-Raphaelite image and a major visual reading of Shakespeare.", "lesson": "Beauty can make tragedy harder, not softer."}, {"title": "The Lady of Shalott", "artist": "John William Waterhouse", "year": "1888", "movement": "Pre-Raphaelite", "location": "Tate Britain, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/John%20William%20Waterhouse%20-%20The%20Lady%20of%20Shalott%20-%20Google%20Art%20Project.jpg", "whySpecial": "Waterhouse turns a literary subject into a mood of isolation, fate and romantic melancholy.", "notice": ["The boat becomes a symbolic passage.", "The tapestry shows a life left behind.", "The figure looks trapped between action and doom.", "Autumn colours deepen the sadness."], "whyKnow": "It is one of the most famous literary paintings of Victorian art.", "lesson": "Narrative painting can feel like a single frame from a larger tragedy."}, {"title": "Judith Slaying Holofernes", "artist": "Artemisia Gentileschi", "year": "c. 1612–1613", "movement": "Baroque", "location": "Museo di Capodimonte, Naples", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Artemisia%20Gentileschi%20-%20Giuditta%20decapita%20Oloferne%20-%20Google%20Art%20Project.jpg", "whySpecial": "Gentileschi gives the biblical scene physical force and psychological intensity. The violence feels immediate, not decorative.", "notice": ["The figures push and pull with real weight.", "The blood is graphic and directional.", "Judith is focused, not passive.", "The dark background intensifies the action."], "whyKnow": "It is a powerful Baroque work and central to Artemisia’s reputation.", "lesson": "Baroque drama is not only theatrical. It can be brutally physical."}, {"title": "Self-Portrait with Thorn Necklace and Hummingbird", "artist": "Frida Kahlo", "year": "1940", "movement": "Modernism / Surrealism", "location": "Harry Ransom Center, Austin", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Frida%20Kahlo%20%28self%20portrait%29.jpg", "whySpecial": "Kahlo turns self-portraiture into symbolic autobiography. Pain, identity, nature and performance sit on the same surface.", "notice": ["The thorn necklace suggests suffering and sacrifice.", "The animals feel symbolic, not decorative.", "Her gaze is direct and unsentimental.", "The lush background presses forward."], "whyKnow": "It shows how self-portraiture can become myth, confession and resistance.", "lesson": "A self-portrait can reveal identity without pretending to be simple."}, {"title": "The Two Fridas", "artist": "Frida Kahlo", "year": "1939", "movement": "Modernism / Surrealism", "location": "Museo de Arte Moderno, Mexico City", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Las%20dos%20Fridas.jpg", "whySpecial": "Kahlo splits herself into two figures, turning heartbreak and identity into a double self-portrait.", "notice": ["The two hearts are visible and exposed.", "The joined hands create connection and division.", "Clothing signals different identities.", "The stormy sky makes emotion external."], "whyKnow": "It is one of the clearest examples of personal symbolism in modern art.", "lesson": "Identity can be painted as a conflict inside one person."}, {"title": "No. 5, 1948", "artist": "Jackson Pollock", "year": "1948", "movement": "Abstract Expressionism", "location": "Private collection", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/No.%205%2C%201948.jpg", "whySpecial": "Pollock turns painting into an arena of action. The image records movement, rhythm and physical process.", "notice": ["Paint is dripped and layered.", "There is no single focal point.", "The surface feels all-over and energetic.", "Gesture becomes the subject."], "whyKnow": "It is a key work of Abstract Expressionism and post-war American art.", "lesson": "Sometimes the artwork is not an image of an action. It is the action."}, {"title": "Campbell’s Soup Cans", "artist": "Andy Warhol", "year": "1962", "movement": "Pop Art", "location": "Museum of Modern Art, New York", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Warhol-Campbell%20Soup-1-screenprint-1968.jpg", "whySpecial": "Warhol makes mass-produced packaging into art, collapsing the distance between consumer culture and the museum.", "notice": ["The repetition feels mechanical.", "The subject is ordinary and commercial.", "Individual expression is deliberately reduced.", "Branding becomes visual language."], "whyKnow": "It is a foundational Pop Art work about mass culture, advertising and repetition.", "lesson": "Modern icons do not only come from churches and palaces. They come from supermarkets too."}, {"title": "The Treachery of Images", "artist": "René Magritte", "year": "1929", "movement": "Surrealism", "location": "Los Angeles County Museum of Art", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/MagrittePipe.jpg", "whySpecial": "Magritte shows a pipe and writes that it is not a pipe. The joke is serious: an image is not the thing itself.", "notice": ["The painting is clear and almost educational.", "The text contradicts what we think we see.", "The style is plain, which makes the idea sharper.", "It turns looking into thinking."], "whyKnow": "It is one of the most important artworks about representation and language.", "lesson": "Art can teach philosophy with one image and one sentence."}, {"title": "The Sleeping Gypsy", "artist": "Henri Rousseau", "year": "1897", "movement": "Naïve Art / Post-Impressionism", "location": "Museum of Modern Art, New York", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Henri%20Rousseau%20005.jpg", "whySpecial": "Rousseau creates a dreamlike desert scene that feels innocent, strange and theatrical.", "notice": ["The lion is calm rather than attacking.", "The figure sleeps in an impossible stillness.", "The moonlight creates mystery.", "The simplified style makes the scene more dreamlike."], "whyKnow": "It shows how non-academic technique can produce powerful modern images.", "lesson": "Naïve does not mean simple-minded. It can mean direct access to dream logic."}, {"title": "The Dance", "artist": "Henri Matisse", "year": "1910", "movement": "Fauvism / Modernism", "location": "Hermitage Museum, Saint Petersburg", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Matissedance.jpg", "whySpecial": "Matisse reduces bodies, colour and rhythm to something almost primal. The painting feels like movement itself.", "notice": ["The palette is radically simple: red, blue and green.", "Bodies form a circular rhythm.", "Anatomy is simplified for energy.", "The broken hand link creates tension."], "whyKnow": "It is one of the great images of modern colour and rhythm.", "lesson": "Modernism often removes detail to intensify feeling."}, {"title": "Woman with a Hat", "artist": "Henri Matisse", "year": "1905", "movement": "Fauvism", "location": "San Francisco Museum of Modern Art", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Henri%20Matisse%2C%201905%2C%20Femme%20au%20chapeau%20%28Woman%20with%20a%20Hat%29%2C%20oil%20on%20canvas%2C%2080.65%20x%2059.69%20cm%2C%20San%20Francisco%20Museum%20of%20Modern%20Art.jpg", "whySpecial": "Matisse uses colour not to describe reality but to create sensation, personality and shock.", "notice": ["Greens, oranges and blues appear on the face.", "Brushwork is loose and visible.", "The portrait is elegant and aggressive.", "Colour becomes structure."], "whyKnow": "It helped define Fauvism and the liberation of colour in modern art.", "lesson": "Colour can be emotional truth, not optical truth."}, {"title": "The Sleeping Venus", "artist": "Giorgione", "year": "c. 1510", "movement": "High Renaissance", "location": "Gemäldegalerie Alte Meister, Dresden", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Giorgione%20-%20Sleeping%20Venus%20-%20Google%20Art%20Project%202.jpg", "whySpecial": "Giorgione creates a model for the reclining nude, linking idealised body, landscape and poetic calm.", "notice": ["The body echoes the curves of the hills.", "The figure is idealised and remote.", "The landscape creates dreamlike stillness.", "The pose influenced centuries of painting."], "whyKnow": "It is crucial for understanding the European tradition of the reclining nude.", "lesson": "A composition can become a visual template for hundreds of years."}, {"title": "Venus of Urbino", "artist": "Titian", "year": "1538", "movement": "Venetian Renaissance", "location": "Uffizi Gallery, Florence", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Tiziano%20-%20Venere%20di%20Urbino%20-%20Google%20Art%20Project.jpg", "whySpecial": "Titian transforms the reclining Venus into a direct, luxurious and psychologically charged image.", "notice": ["The gaze is direct and confident.", "The warm colour is characteristically Venetian.", "The dog suggests domestic intimacy or loyalty.", "The background figures add narrative ambiguity."], "whyKnow": "It shaped later nude painting, including Manet’s Olympia.", "lesson": "Art history is often a chain of artists answering earlier images."}, {"title": "The Burial of the Count of Orgaz", "artist": "El Greco", "year": "1586–1588", "movement": "Mannerism / Spanish Renaissance", "location": "Church of Santo Tomé, Toledo", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/El%20Greco%20-%20The%20Burial%20of%20the%20Count%20of%20Orgaz.JPG", "whySpecial": "El Greco joins earthly ceremony and heavenly vision in one elongated, spiritual composition.", "notice": ["The lower half is solemn and earthly.", "The upper half is ecstatic and vertical.", "Figures are elongated and flame-like.", "The painting connects Toledo society to divine drama."], "whyKnow": "It is a masterpiece of Spanish Mannerism and spiritual intensity.", "lesson": "Style can stretch reality to express faith and emotion."}, {"title": "View of Toledo", "artist": "El Greco", "year": "c. 1596–1600", "movement": "Mannerism", "location": "Metropolitan Museum of Art, New York", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/View%20of%20Toledo%20MET%20DP349620.jpg", "whySpecial": "El Greco turns a city view into a storm of spiritual intensity and unstable light.", "notice": ["The sky feels apocalyptic.", "The city is rearranged for expressive power.", "Green and blue dominate the mood.", "The landscape feels alive and anxious."], "whyKnow": "It is one of the most famous expressive landscapes before modernism.", "lesson": "A city can be painted like a state of mind."}, {"title": "The Calling of Saint Matthew", "artist": "Caravaggio", "year": "1599–1600", "movement": "Baroque", "location": "Contarelli Chapel, Rome", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/The%20Calling%20of%20Saint%20Matthew-Caravaggo%20%281599-1600%29.jpg", "whySpecial": "Caravaggio turns a religious calling into a moment inside a dark Roman room. Grace arrives like a beam of light.", "notice": ["The light cuts across the scene dramatically.", "Christ’s gesture echoes Michelangelo’s Creation of Adam.", "The figures look like ordinary people.", "The moment is spiritual but physically grounded."], "whyKnow": "It is a key work of Baroque realism and dramatic lighting.", "lesson": "Caravaggio makes the sacred feel like it entered real life."}, {"title": "The Conversion of Saint Paul", "artist": "Caravaggio", "year": "1601", "movement": "Baroque", "location": "Santa Maria del Popolo, Rome", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Caravaggio%20-%20Conversion%20on%20the%20Way%20to%20Damascus.jpg", "whySpecial": "Caravaggio paints spiritual conversion not as spectacle, but as a body thrown into darkness and light.", "notice": ["The horse dominates the composition.", "Paul is vulnerable on the ground.", "Light creates the miracle without showing heaven.", "The scene is compressed and intense."], "whyKnow": "It shows Caravaggio’s radical physical approach to religious subjects.", "lesson": "The divine can be shown through impact rather than decoration."}, {"title": "The Oath of the Horatii", "artist": "Jacques-Louis David", "year": "1784", "movement": "Neoclassicism", "location": "Louvre Museum, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Jacques-Louis%20David%2C%20Le%20Serment%20des%20Horaces.jpg", "whySpecial": "David turns civic duty into severe geometry and moral drama.", "notice": ["The men form hard, angular lines.", "The women collapse into curves of grief.", "The arches organise the scene.", "The swords are the compositional centre."], "whyKnow": "It is a defining work of Neoclassicism and pre-Revolutionary moral seriousness.", "lesson": "Composition can make ideology visible."}, {"title": "The Death of Marat", "artist": "Jacques-Louis David", "year": "1793", "movement": "Neoclassicism", "location": "Royal Museums of Fine Arts of Belgium, Brussels", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Death%20of%20Marat%20by%20David.jpg", "whySpecial": "David turns a murdered revolutionary into a secular martyr with stark simplicity.", "notice": ["The background is almost empty.", "Marat’s body echoes religious images of martyrdom.", "The letter identifies the political story.", "The restraint makes the image more powerful."], "whyKnow": "It is a major work of revolutionary propaganda and political mourning.", "lesson": "Political images borrow religious visual language to create belief."}, {"title": "Napoleon Crossing the Alps", "artist": "Jacques-Louis David", "year": "1801", "movement": "Neoclassicism", "location": "Various versions", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Jacques-Louis%20David%20-%20Bonaparte%20franchissant%20le%20Grand-Saint-Bernard%2C%2020%20mai%201800%20-%20Google%20Art%20Project.jpg", "whySpecial": "David turns Napoleon into myth: controlled, heroic and larger than weather, history and terrain.", "notice": ["The horse rears dramatically.", "Napoleon points upward and forward.", "Names on the rocks link him to earlier conquerors.", "The reality was much less glamorous."], "whyKnow": "It is a classic example of image-making as political branding.", "lesson": "Portraits of power often sell a story, not a fact."}, {"title": "The Gross Clinic", "artist": "Thomas Eakins", "year": "1875", "movement": "Realism", "location": "Philadelphia Museum of Art", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Thomas%20Eakins%2C%20American%20-%20Portrait%20of%20Dr.%20Samuel%20D.%20Gross%20%28The%20Gross%20Clinic%29%20-%20Google%20Art%20Project.jpg", "whySpecial": "Eakins makes modern surgery into a serious public drama of science, skill and discomfort.", "notice": ["The doctor stands like an intellectual hero.", "The surgery is graphic for its time.", "The theatre setting shows medicine as public knowledge.", "Light separates authority from shock."], "whyKnow": "It is a major American realist painting about science and modern professionalism.", "lesson": "Realism can make expertise look heroic and unsettling at once."}, {"title": "Arrangement in Grey and Black No. 1", "artist": "James McNeill Whistler", "year": "1871", "movement": "Realism / Aestheticism", "location": "Musée d’Orsay, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Whistlers%20Mother%20high%20res.jpg", "whySpecial": "Known as Whistler’s Mother, this work is also an exercise in tonal harmony and formal balance.", "notice": ["The seated profile creates stillness.", "Greys and blacks dominate the mood.", "Rectangles repeat across the composition.", "Emotion is restrained."], "whyKnow": "It helps explain Aestheticism: art valued for arrangement and harmony.", "lesson": "Subject matters, but structure can be the real engine."}, {"title": "Barge Haulers on the Volga", "artist": "Ilya Repin", "year": "1870–1873", "movement": "Realism", "location": "Russian Museum, Saint Petersburg", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Repin%20Barge%20Haulers.jpg", "whySpecial": "Repin paints labour with dignity, exhaustion and social force.", "notice": ["The line of workers creates rhythm and burden.", "Each face is individualised.", "The bright landscape contrasts with hardship.", "The boy near the centre suggests resistance."], "whyKnow": "It is a landmark of Russian Realism and social consciousness.", "lesson": "Realism can be political simply by refusing to look away."}, {"title": "The Ninth Wave", "artist": "Ivan Aivazovsky", "year": "1850", "movement": "Romanticism", "location": "Russian Museum, Saint Petersburg", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Ivan%20Aivazovsky%20-%20The%20Ninth%20Wave.jpg", "whySpecial": "Aivazovsky makes shipwreck sublime: terrifying sea, glowing light and fragile survival.", "notice": ["The wave feels enormous but beautiful.", "Warm sunrise light complicates the danger.", "Survivors cling to wreckage.", "Nature is both enemy and spectacle."], "whyKnow": "It is one of the most famous maritime paintings in Russian art.", "lesson": "The sublime can make danger visually irresistible."}, {"title": "The Ancient of Days", "artist": "William Blake", "year": "1794", "movement": "Romanticism / Symbolism", "location": "British Museum, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Europe%20a%20Prophecy%20copy%20K%20plate%2001.jpg", "whySpecial": "Blake imagines creation as cosmic measurement, combining poetry, religion and personal mythology.", "notice": ["The figure bends within a flaming circle.", "The compass suggests creation through geometry.", "The body is powerful and strained.", "The image feels symbolic rather than descriptive."], "whyKnow": "It is one of Blake’s most iconic images of visionary art.", "lesson": "Some artists build private mythologies instead of illustrating shared ones."}, {"title": "The Blue Boy", "artist": "Thomas Gainsborough", "year": "c. 1770", "movement": "Rococo / British Portraiture", "location": "Huntington Library, California", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Thomas%20Gainsborough%20-%20The%20Blue%20Boy%20%28Huntington%20Library%29.jpg", "whySpecial": "Gainsborough turns a portrait into a display of colour, aristocratic pose and painterly elegance.", "notice": ["Blue dominates the image with confidence.", "The costume looks historical, not contemporary.", "The pose is theatrical.", "Brushwork gives fabric a living surface."], "whyKnow": "It is one of the most famous British portraits.", "lesson": "Portraits can sell identity through costume, colour and attitude."}, {"title": "Madame X", "artist": "John Singer Sargent", "year": "1884", "movement": "Realism / Society Portraiture", "location": "Metropolitan Museum of Art, New York", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Madame%20X%20%28Madame%20Pierre%20Gautreau%29%2C%20John%20Singer%20Sargent%2C%201884%20%28unfree%20frame%20crop%29.jpg", "whySpecial": "Sargent created a portrait of elegance so sharp that it became scandalous.", "notice": ["The profile is severe and sculptural.", "The black dress creates dramatic contrast.", "The pose feels controlled but provocative.", "The skin is painted with cool luminosity."], "whyKnow": "It is a landmark of society portraiture and public scandal.", "lesson": "Style can become dangerous when it appears too self-aware."}, {"title": "Carnation, Lily, Lily, Rose", "artist": "John Singer Sargent", "year": "1885–1886", "movement": "Impressionism / Aestheticism", "location": "Tate Britain, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/John%20Singer%20Sargent%20-%20Carnation%2C%20Lily%2C%20Lily%2C%20Rose%20-%20Google%20Art%20Project.jpg", "whySpecial": "Sargent captures twilight, childhood and lantern light with delicate precision.", "notice": ["The lanterns glow against dusk.", "The children are absorbed in action.", "Flowers create a decorative frame.", "The mood is fragile and temporary."], "whyKnow": "It shows how light can become the true subject of a painting.", "lesson": "Some paintings are about a time of day more than an event."}, {"title": "The Horse Fair", "artist": "Rosa Bonheur", "year": "1852–1855", "movement": "Realism", "location": "Metropolitan Museum of Art, New York", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Rosa%20Bonheur%20-%20The%20Horse%20Fair%20-%20Google%20Art%20Project.jpg", "whySpecial": "Bonheur gives animal painting monumental scale and physical force.", "notice": ["The horses create circular motion.", "Muscles and movement are closely observed.", "The scene is energetic but controlled.", "The scale gives animals heroic presence."], "whyKnow": "It is a major nineteenth-century work by one of the era’s most successful women artists.", "lesson": "Observation and ambition can turn genre painting into spectacle."}, {"title": "The Crystal Palace", "artist": "Camille Pissarro", "year": "1871", "movement": "Impressionism", "location": "Art Institute of Chicago", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Camille%20Pissarro%20-%20The%20Crystal%20Palace%20-%20Google%20Art%20Project.jpg", "whySpecial": "Pissarro treats modern urban life with atmospheric light and loose observation.", "notice": ["The building is filtered through weather and distance.", "Figures are small and everyday.", "Brushwork softens the scene.", "Modern architecture becomes part of landscape."], "whyKnow": "It helps show Impressionism outside the usual river-and-garden clichés.", "lesson": "Modernity can appear quietly, through atmosphere."}, {"title": "Bal du moulin de la Galette", "artist": "Pierre-Auguste Renoir", "year": "1876", "movement": "Impressionism", "location": "Musée d’Orsay, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Pierre-Auguste%20Renoir%2C%20Le%20Moulin%20de%20la%20Galette.jpg", "whySpecial": "Renoir captures modern leisure as flickering light, movement and social pleasure.", "notice": ["Dappled light falls across figures.", "The crowd feels lively but organised.", "Faces emerge from atmosphere.", "The scene feels like a remembered afternoon."], "whyKnow": "It is one of the great Impressionist images of Parisian social life.", "lesson": "Impressionism often paints the feeling of being there, not the inventory of details."}, {"title": "The Floor Scrapers", "artist": "Gustave Caillebotte", "year": "1875", "movement": "Realism / Impressionism", "location": "Musée d’Orsay, Paris", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:Gustave%20Caillebotte%20-%20Les%20raboteurs%20de%20parquet.jpg", "whySpecial": "Caillebotte makes urban labour modern, physical and strangely elegant.", "notice": ["The perspective pushes into the room.", "The workers’ bodies repeat in rhythm.", "The floor reflects light beautifully.", "The subject is ordinary but monumental."], "whyKnow": "It expands what modern painting could consider worthy of attention.", "lesson": "Modern life includes work, surfaces and bodies in motion."}, {"title": "Paris Street; Rainy Day", "artist": "Gustave Caillebotte", "year": "1877", "movement": "Realism / Impressionism", "location": "Art Institute of Chicago", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Gustave%20Caillebotte%20-%20Paris%20Street%3B%20Rainy%20Day%20-%201964.336%20-%20Art%20Institute%20of%20Chicago.jpg", "whySpecial": "Caillebotte makes a rainy Paris street feel cinematic, modern and psychologically distant.", "notice": ["The wide street shows Haussmann’s new Paris.", "Umbrellas create repeating shapes.", "Figures are close but emotionally separate.", "The cropping feels photographic."], "whyKnow": "It is a key image of modern urban experience.", "lesson": "Modernity often feels spacious and lonely at once."}, {"title": "The Gulf Stream", "artist": "Winslow Homer", "year": "1899", "movement": "Realism", "location": "Metropolitan Museum of Art, New York", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Winslow%20Homer%20-%20The%20Gulf%20Stream%20-%20Metropolitan%20Museum%20of%20Art.jpg", "whySpecial": "Homer paints survival at sea with ambiguity, danger and psychological restraint.", "notice": ["The broken boat is surrounded by sharks.", "The man appears calm or resigned.", "The sea dominates the scene.", "A distant ship may or may not mean rescue."], "whyKnow": "It is a powerful American painting about nature, race, danger and uncertainty.", "lesson": "Ambiguity can make danger more haunting."}, {"title": "Watson and the Shark", "artist": "John Singleton Copley", "year": "1778", "movement": "History Painting", "location": "National Gallery of Art, Washington", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Watson%20and%20the%20Shark.jpg", "whySpecial": "Copley turns a real shark attack into dramatic history painting.", "notice": ["The figures reach toward the victim in a triangle.", "The shark is terrifying but stylised.", "The water creates chaos.", "Rescue and danger happen in the same moment."], "whyKnow": "It shows how dramatic composition could elevate a modern event.", "lesson": "History painting is often theatre built from crisis."}, {"title": "Rain, Steam and Speed", "artist": "J. M. W. Turner", "year": "1844", "movement": "Romanticism", "location": "National Gallery, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Joseph%20Mallord%20William%20Turner%20-%20Rain%2C%20Steam%20and%20Speed%20-%20The%20Great%20Western%20Railway%20-%20Google%20Art%20Project.jpg", "whySpecial": "Turner makes modern speed dissolve into weather, light and sensation.", "notice": ["The train emerges from mist and rain.", "Forms blur into atmosphere.", "The bridge creates forward thrust.", "Technology becomes almost sublime."], "whyKnow": "It is a key image of industrial modernity in painting.", "lesson": "Modern life can be painted as speed and atmosphere."}, {"title": "Dido Building Carthage", "artist": "J. M. W. Turner", "year": "1815", "movement": "Romanticism", "location": "National Gallery, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Joseph%20Mallord%20William%20Turner%20-%20Dido%20building%20Carthage%20-%20Google%20Art%20Project.jpg", "whySpecial": "Turner uses classical history as a stage for radiant light and imperial ambition.", "notice": ["The sun dominates the composition.", "Architecture glows through atmosphere.", "Tiny figures create scale.", "History becomes luminous and fragile."], "whyKnow": "It shows Turner competing with Claude and the grand landscape tradition.", "lesson": "Light can be the real protagonist."}, {"title": "The Embarkation of the Queen of Sheba", "artist": "Claude Lorrain", "year": "1648", "movement": "Baroque / Classical Landscape", "location": "National Gallery, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Claude%20Lorrain%20-%20Seaport%20with%20the%20Embarkation%20of%20the%20Queen%20of%20Sheba%20-%20Google%20Art%20Project.jpg", "whySpecial": "Claude turns a biblical episode into an ideal harbour of light, architecture and calm order.", "notice": ["The rising sun organises the scene.", "Architecture frames the harbour.", "Figures are small against the setting.", "The atmosphere is golden and balanced."], "whyKnow": "It shaped European landscape painting for centuries.", "lesson": "Classical landscape is less about weather and more about ideal order."}, {"title": "The Hunters in the Snow", "artist": "Pieter Bruegel the Elder", "year": "1565", "movement": "Northern Renaissance", "location": "Kunsthistorisches Museum, Vienna", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Pieter%20Bruegel%20the%20Elder%20-%20Hunters%20in%20the%20Snow%20%28Winter%29%20-%20Google%20Art%20Project.jpg", "whySpecial": "Bruegel makes winter communal, harsh and beautiful without turning peasants into decoration.", "notice": ["Hunters return tired with dogs.", "The valley opens into a vast winter world.", "Small figures skate and work below.", "The palette is cold but lively."], "whyKnow": "It is one of the great seasonal landscapes in Western art.", "lesson": "A landscape can contain a whole society."}, {"title": "The Tower of Babel", "artist": "Pieter Bruegel the Elder", "year": "1563", "movement": "Northern Renaissance", "location": "Kunsthistorisches Museum, Vienna", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:Pieter%20Bruegel%20the%20Elder%20-%20The%20Tower%20of%20Babel%20%28Vienna%29%20-%20Google%20Art%20Project.jpg", "whySpecial": "Bruegel turns the biblical tower into a massive image of ambition, labour and collapse.", "notice": ["The tower is both impressive and unstable.", "Tiny workers show human scale.", "Architecture resembles Roman ruins.", "The city below makes the project political."], "whyKnow": "It is a powerful image of human ambition and structural failure.", "lesson": "Grand projects can reveal weakness as much as power."}, {"title": "The Ghent Altarpiece", "artist": "Hubert and Jan van Eyck", "year": "1432", "movement": "Northern Renaissance", "location": "St Bavo’s Cathedral, Ghent", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:Retable%20de%20l%27Agneau%20mystique.jpg", "whySpecial": "The Ghent Altarpiece is a monumental work of devotion, detail and luminous oil painting.", "notice": ["The panels combine heavenly and earthly realms.", "Textures are painted with astonishing precision.", "The lamb is central to the theology.", "The scale creates an immersive experience."], "whyKnow": "It is one of the foundational masterpieces of Northern Renaissance art.", "lesson": "Technical detail can become spiritual intensity."}, {"title": "The Isenheim Altarpiece", "artist": "Matthias Grünewald", "year": "1512–1516", "movement": "Northern Renaissance", "location": "Unterlinden Museum, Colmar", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:Matthias%20Gr%C3%BCnewald%20-%20The%20Crucifixion%20-%20WGA10702.jpg", "whySpecial": "Grünewald’s Crucifixion is physically agonising and emotionally extreme.", "notice": ["Christ’s body is twisted and wounded.", "The darkness intensifies suffering.", "Hands and gestures carry emotional force.", "The image was made for a hospital context."], "whyKnow": "It is one of the most intense religious images in European art.", "lesson": "Compassion can be created through discomfort."}, {"title": "The Laughing Cavalier", "artist": "Frans Hals", "year": "1624", "movement": "Dutch Golden Age", "location": "Wallace Collection, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:Frans%20Hals%20-%20Laughing%20Cavalier.jpg", "whySpecial": "Hals makes portraiture feel alive through swagger, brushwork and expression.", "notice": ["The moustache and smile create confidence.", "The costume is richly patterned.", "The pose is turned and lively.", "Brushwork gives energy to the surface."], "whyKnow": "It is a famous example of Dutch portrait bravura.", "lesson": "A portrait can perform personality, not just record appearance."}, {"title": "The Anatomy Lesson of Dr. Nicolaes Tulp", "artist": "Rembrandt van Rijn", "year": "1632", "movement": "Dutch Golden Age / Baroque", "location": "Mauritshuis, The Hague", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:The%20Anatomy%20Lesson.jpg", "whySpecial": "Rembrandt turns a medical demonstration into a drama of knowledge, attention and status.", "notice": ["The corpse anchors the composition.", "Faces show different degrees of attention.", "The doctor’s hand explains the anatomy.", "Light creates intellectual theatre."], "whyKnow": "It is a key work of Dutch group portraiture and scientific culture.", "lesson": "Knowledge can be staged like drama."}, {"title": "Self-Portrait with Two Circles", "artist": "Rembrandt van Rijn", "year": "c. 1665–1669", "movement": "Dutch Golden Age", "location": "Kenwood House, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:Rembrandt%20Self-portrait%20%28Kenwood%29.jpg", "whySpecial": "Late Rembrandt presents himself as aged, direct and painterly, without vanity.", "notice": ["The face is built with rough, living brushwork.", "The circles behind him remain mysterious.", "The pose is calm and authoritative.", "The painting feels honest rather than polished."], "whyKnow": "It is one of the great artist self-portraits.", "lesson": "A self-portrait can be a statement about what painting itself can do."}, {"title": "The Jewish Bride", "artist": "Rembrandt van Rijn", "year": "c. 1665–1669", "movement": "Dutch Golden Age", "location": "Rijksmuseum, Amsterdam", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:Rembrandt%20Harmensz.%20van%20Rijn%20-%20Het%20Joodse%20bruidje.jpg", "whySpecial": "Rembrandt paints tenderness through touch, texture and quiet gravity.", "notice": ["The hands are emotionally central.", "Paint is thick and jewel-like.", "The figures are close but restrained.", "The mood is intimate and solemn."], "whyKnow": "It is one of Rembrandt’s most moving late works.", "lesson": "Touch can carry more feeling than facial expression."}, {"title": "The Rokeby Venus", "artist": "Diego Velázquez", "year": "1647–1651", "movement": "Spanish Baroque", "location": "National Gallery, London", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:Velazquez%20Rokeby%20Venus.jpg", "whySpecial": "Velázquez paints Venus from behind, turning beauty, reflection and distance into a subtle puzzle.", "notice": ["The mirror shows a blurred face.", "The pose is sensual but restrained.", "Cupid holds the mirror awkwardly.", "The palette is soft and controlled."], "whyKnow": "It is one of the few surviving Spanish nudes of the period.", "lesson": "A mirror in painting often complicates desire and looking."}, {"title": "The Surrender of Breda", "artist": "Diego Velázquez", "year": "1634–1635", "movement": "Spanish Baroque", "location": "Museo del Prado, Madrid", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:Velazquez-The%20Surrender%20of%20Breda.jpg", "whySpecial": "Velázquez turns military victory into a scene of dignity and restraint.", "notice": ["The handover of keys is calm, not brutal.", "The lances create visual rhythm.", "Both sides are given human presence.", "The landscape opens behind the figures."], "whyKnow": "It is a major example of Spanish Baroque history painting.", "lesson": "Power can be represented through mercy as much as force."}, {"title": "The Maids of Honour", "artist": "Diego Velázquez", "year": "1656", "movement": "Spanish Baroque", "location": "Museo del Prado, Madrid", "image": "https://commons.wikimedia.org/wiki/Special:FilePath/Las%20Meninas%2C%20by%20Diego%20Vel%C3%A1zquez%2C%20from%20Prado%20in%20Google%20Earth.jpg", "whySpecial": "Velázquez turns court portraiture into a question about art, power and looking.", "notice": ["The painter appears inside the painting.", "The mirror shows the monarchs.", "The princess is central but not the only subject.", "The viewer becomes part of the scene."], "whyKnow": "It is one of art history’s great paintings about perception.", "lesson": "The act of looking can become the subject."}, {"title": "The Burial of the Sardine", "artist": "Francisco Goya", "year": "c. 1812–1819", "movement": "Romanticism", "location": "Real Academia de Bellas Artes de San Fernando, Madrid", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:El%20entierro%20de%20la%20sardina%20%28Goya%29.jpg", "whySpecial": "Goya paints carnival as collective madness, energy and social release.", "notice": ["The crowd is loose and chaotic.", "Faces verge on masks.", "Movement dominates order.", "The mood is festive but unsettling."], "whyKnow": "It shows Goya’s fascination with crowds, irrationality and social theatre.", "lesson": "Celebration can look very close to disorder."}, {"title": "Saturn Devouring His Son", "artist": "Francisco Goya", "year": "1819–1823", "movement": "Romanticism / Black Paintings", "location": "Museo del Prado, Madrid", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:Francisco%20de%20Goya%2C%20Saturno%20devorando%20a%20su%20hijo%20%281819-1823%29.jpg", "whySpecial": "Goya’s mythological horror feels private, raw and psychologically extreme.", "notice": ["The dark background removes context.", "Saturn’s eyes are wild.", "The body is brutally handled.", "The brushwork feels urgent."], "whyKnow": "It is one of the most haunting images from Goya’s Black Paintings.", "lesson": "Some art feels like it was pulled from a nightmare rather than designed."}, {"title": "The Clothed Maja", "artist": "Francisco Goya", "year": "c. 1800–1807", "movement": "Romanticism", "location": "Museo del Prado, Madrid", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:La%20maja%20vestida%20%28Goya%29.jpg", "whySpecial": "Goya’s Maja challenges conventions of gaze, class and display.", "notice": ["The pose is direct and confident.", "Clothing becomes part of the provocation.", "The figure meets the viewer’s gaze.", "The image pairs with the Nude Maja."], "whyKnow": "It is important for understanding Goya’s modern treatment of spectatorship.", "lesson": "The gaze can be as provocative as nudity."}, {"title": "The Nude Maja", "artist": "Francisco Goya", "year": "c. 1797–1800", "movement": "Romanticism", "location": "Museo del Prado, Madrid", "image": "https://commons.wikimedia.org/wiki/Special:FilePath:La%20maja%20desnuda%20%28Goya%29.jpg", "whySpecial": "Goya paints a nude woman without mythological disguise, creating directness unusual for its time.", "notice": ["The gaze is direct.", "The pose is frontal and self-possessed.", "The setting is minimal.", "The painting caused controversy."], "whyKnow": "It helps explain later modern nudes, including Manet.", "lesson": "Removing the myth can make an image more modern and more dangerous."}];
